  ('ba1cdc41-9c95-49b7-9a04-55f049379838'::uuid, '48b8026f-574a-48f0-b10e-d2fb85d8b32a'::uuid, null, 'product_updated', 'manufacturer_scraper_auto_review', '{"id":"48b8026f-574a-48f0-b10e-d2fb85d8b32a","title":"DHC Oral Clear SS-K12 30-Day Supply","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"17f6ebfb-bc28-4471-84e6-12fccfd93e06","category":null,"currency":"THB","platform":"manual","title_en":"DHC Oral Clear SS-K12 30-Day Supply","title_th":"DHC โอรัลเคลียร์ SS-K12 30 วัน","image_url":"https://www.dhc.co.jp/dw/image/v2/BLLL_PRD/on/demandware.static/-/Sites-dhc_catalog-ms/default/dw6b54a063/large/32408/32408_G.png?sw=256&sh=256&sm=cut","brand_name":"dhc","created_at":"2026-05-21T10:14:17.849642+00:00","source_url":"https://www.dhc.co.jp/goods/32408.html","updated_at":"2026-05-21T10:14:17.860129+00:00","admin_notes":null,"description":"歯磨きあとの新習慣！ なめて、溶かして、息さわやか※","product_url":"https://www.dhc.co.jp/goods/32408.html","label_status":"missing","price_amount":null,"product_kind":"supplement","description_en":"Oral lozenge containing Streptococcus salivarius K12 probiotic, cranberry extract and polyglutamic acid for fresh breath after brushing.","description_th":"เม็ดอมสำหรับช่องปาก ประกอบด้วยโปรไบโอติก Streptococcus salivarius K12 สารสกัดแครนเบอร์รี่ และโพลีกลูตามิกแอซิด ช่วยให้ลมหายใจสดชื่นหลังแปรงฟัน","normalized_url":"https://www.dhc.co.jp/goods/32408.html","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"locale":"ja","parser":"dhc_demandware_health_supplements_v1","titleEn":"DHC Oral Clear SS-K12 30-Day Supply","titleTh":"DHC โอรัลเคลียร์ SS-K12 30 วัน","htmlHash":"ff6e679104f55d5db9f38d74be9f9e21a3319cc0c7f8d0de13e75c3acee02dd9","nutrition":"「お口の健康が気になる」、「さわやかな息でいたい」。そんな方におすすめなのが『オーラルクリアSS-K12』。なめて、お口の中で溶かして摂る新感覚のサプリです。 『オーラルクリアSS-K12』には口腔内に存在する善玉菌SS-K12のほか、サポート成分として、クランベリーエキスやうるおい成分ポリグルタミン酸を加えました。おいしく続けられるよう、プラム風味に仕上げ、甘みにはキシリトールを使用しました。 ネバつきなどお口の不快感や息が気になる方はもちろん、お子様にもおすすめです。毎日の積み重ねで環境を整える新習慣をはじめましょう。 ※マスキング効果による JANコード： 4511413620403 なめて、口の中でゆっくり溶かしてお召し上がりください。 夜の歯みがき後、寝る前に摂るのがおすすめです。 ※噛まずに口の中でゆっくり溶かしてお召し上がりください。 ※本品は天然素材を使用しているため、色調に若干差が生じる場合があります。これは色の調整をしていないためであり、成分含有量や品質に問題はありません。 ※配合成分のキシリトールは、人間にとって有用な成分ですが、動物には悪影響を与える危険があります。これは、動物の生理機能が人間とは異なるためです。ペットが誤って食べないよう充分ご注意ください。 【名称】乳酸菌（生菌）利用食品 【原材料名】還元麦芽糖水飴（国内製造）、デキストリン、クランベリーエキス末、乳酸菌末（乳成分を含む）/甘味料（キシリトール）、ソルビトール、セルロース、ステアリン酸Ca、微粒二酸化ケイ素、香料、納豆菌ガム（大豆由来） 【内容量】30.0g（1粒重量1000mg×30粒） 【栄養成分表示［1粒1000mgあたり］】熱量4.0kcal、たんぱく質0.01g、脂質0.03g、炭水化物0.92g、食塩相当量0.003g、乳酸菌末（ストレプトコッカス・サリバリウスK12）8mg、クランベリーエキス末10mg、ポリグルタミン酸5mg アレルギー物質 乳 大豆 健康食品について ※一日摂取目安量を守って、お召し上がりください。 ※お身体に異常を感じた場合は、摂取を中止してください。 ※特定原材料及びそれに準ずるアレルギー物質を対象範囲として表示しています。原材料をご確認の上、食物アレルギーのある方はお召し上がりにならないでください。 ※薬を服用中あるいは通院中の方、妊娠中の方は、お医者様にご相談の上お召し上がりください。 ●直射日光、高温多湿な場所をさけて保存してください。 ●お子様の手の届かないところで保管してください。 ●開封後はしっかり開封口を閉め、なるべく早くお召し上がりください。 食生活は、主食、主菜、副菜を基本に、食事のバランスを。 レビュー 2025年以前のレビュー 寝起きの口がスッキリ 2020年02月07日 岡田敦子 ｜ 愛用歴：0年6ヶ月 ｜ 愛知県 ｜ 41歳 前から気になってたオーラルクリア。 とどいたその日から、早速舐めて見ました。 朝起きて、いつもより口の中がスッキリしてる！と感激です。 関連する商品 キャンペーン 送料無料 ネコポス コンビニ受取 香るブルガリアンローズカプセル 30日分 3個セット 5,427 円 4,752 円（税込） 12%off 7月29日まで カートに入れる キャンペーン ネコポス コンビニ受取 亜鉛 30日分 3個セット 810 円 783 円（税込） 3%off 6月2日まで カートに入れる キャンペーン ネコポス コンビニ受取 デオガード 30日分 2個セット 4,266 円 3,618 円（税込） 15%off 6月2日まで カートに入れる キャンペーン 送料無料 ネコポス コンビニ受取 ボリュームトップ 30日分 2個セット 6,534 円 5,670 円（税込） 13%off 6月2日まで カートに入れる 関連カテゴリ 健康食品・サプリメント 健康食品・サプリメント 目的で探す 見た目・ニオイ 健康食品・サプリメント 健康食品・サプリメント 人気成分で探す 乳酸菌・ビフィズス菌 カートに追加しました この商品はすでにお気に入りリストに追加されています。 新作アイテム今すぐチェック --> 新作アイテム 今すぐチェック 新作アイテム今すぐチェック --> お買い得商品を お見逃しなく！ 新作アイテム今すぐチェック --> 最大25％OFF 業界最大級の割引率 新作アイテム今すぐチェック --> オンラインショップ 限定品 新作アイテム今すぐチェック --> 安全性を第一に考えた 製品づくり 新作アイテム今すぐチェック --> 読み物や特集ページは コチラ お得な購入特典 すべて見る 最大10%OFF！ 一括購入割引 税込3,780円以上のご購入で、 当社が送料を負担","productId":"32408","validation":{"status":"failed","reasons":["no_canonical_match","no_dosed_facts"],"summary":"No usable per-serving product facts.","checkedAt":"2026-05-21T10:14:17.857Z","matchableFactCount":0},"description":"歯磨きあとの新習慣！ なめて、溶かして、息さわやか