  ('bf9cfec2-5707-4f20-b622-3c3b4e5f310d'::uuid, '039b6d25-83d0-4f27-b178-7eb0bd29ae0a'::uuid, null, 'product_updated', 'admin_dashboard', '{"id":"039b6d25-83d0-4f27-b178-7eb0bd29ae0a","title":"Blackmores St John&#x27;s Wort","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"40e4806a-5049-4668-8d29-ab36a31202dd","category":null,"currency":"THB","platform":"manual","title_en":"Blackmores St John&#x27;s Wort","title_th":null,"image_url":"https://images.contentstack.io/v3/assets/blt948bd74310fc0ad0/blt46d9a93b3583e982/68c36ce4b1494da1344fb2a2/93493178-1.webp","brand_name":"blackmores","created_at":"2026-05-21T13:09:48.406067+00:00","source_url":"https://www.blackmores.com.au/products/st-johns-wort","updated_at":"2026-05-21T13:09:48.414986+00:00","admin_notes":null,"description":"St John&#x27;s wort is traditionally used in Western herbal medicine to support healthy mood balance & relieve symptoms of mild anxiety.","product_url":"https://www.blackmores.com.au/products/st-johns-wort","label_status":"missing","price_amount":null,"product_kind":"supplement","description_en":"St John&#x27;s wort is traditionally used in Western herbal medicine to support healthy mood balance & relieve symptoms of mild anxiety.","description_th":null,"normalized_url":"https://www.blackmores.com.au/products/st-johns-wort","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"dosage":"for use. Read the","locale":"en","parser":"blackmores_structured_ingredients_v2","titleEn":"Blackmores St John&#x27;s Wort","htmlLength":162767,"validation":{"status":"failed","reasons":["no_canonical_match","no_dosed_facts"],"summary":"No usable per-serving product facts.","checkedAt":"2026-05-21T13:09:48.413Z","matchableFactCount":0},"description":"St John&#x27;s wort is traditionally used in Western herbal medicine to support healthy mood balance & relieve symptoms of mild anxiety.","descriptionEn":"St John&#x27;s wort is traditionally used in Western herbal medicine to support healthy mood balance & relieve symptoms of mild anxiety.","descriptionTh":null,"extractedText":"St Johns Wort All Products Shop All Products New Products Best Sellers Vegan Certified Women&#x27;s Health Men&#x27;s Health Kid&#x27;s Health Infant & Toddler Nutrition By Category Arthritis, Joint & Bone Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutritional Oils Heart Health Infant & Toddler Nutrition Kids&#x27; Health Men&#x27;s Health Multivitamins Muscle Support Nails, Hair & Skin Preconception, Pregnancy & Breastfeeding Stress Relief & Sleep Support Women&#x27;s Health By Ingredient Calcium CoQ10 Curcumin Echinacea Fish Oil & Omega 3 Glucosamine Iron Magnesium Probiotics Selenium Vitamin B Vitamin C Vitamin D Vitamin E Zinc Health Hub By Categories By Type Latest Articles Action Plans Arthritis, Bone & Joint Beauty & Skincare Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutrition Oils Heart & Cardiovascular Health Kids & Infant Health Men&#x27;s Health Muscle Support & Fitness Preconception, Pregnancy & Breastfeeding Recipes Stress Relief & Sleep Support Women&#x27;s Health Action Plans Articles Recipes Latest Articles About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Pillars Our People & Culture Our Careers Our Ambassadors & Partners Contact us Ask A Naturopath Our Newsroom Blackmores Subscribe Search Home Chevron Icon Horizontal products Chevron Icon Horizontal Blackmores St John&#x27;s Wort Size Size 90 tablets BLACKMORES St John’s Wort contains St John’s Wort, traditionally used in Western herbal medicine to relieve symptoms of mild anxiety, and support healthy mood balance. Designed as a natural option to relieve nervous tension, this formula offers a plant-based approach to support healthy emotional balance. It is suitable for individuals seeking herbal support in times of mild emotional unrest. Good health changes everything—support your mood with BLACKMORES St John’s Wort. Product Format Tablet Always read the label and follow the directions for use. Read the warnings before purchase. Support For Mild Anxiety Nervous Tension Mood Balance Halal Certified No Added Yeast No Added Gluten No Added Wheat No Added Dairy Benefits & How To Use Benefits Contains an extract of St John&#x27;s Wort standardised to hypericin. Traditionally used in Western herbal medicine to: Relieve symptoms of mild anxiety. Support healthy mood balance. Relieve nervous tension. Dosage Adults Take 1 tablet three times a day, or as prescribed by a health professional. Take with food. Warnings Always read the label and follow the directions for use. Do not during pregnancy or when breastfeeding. St John’s Wort affects the way many prescriptions medicines work -including the oral contraceptive pill. If you are taking other medicines, consult your doctor before use. Avoid excessive skin exposure to sunlight and sunlamps while taking this product. If symptoms persist, talk to your health professional. If you have any pre-existing conditions or are on any medications always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains soya bean products. Benefits Dosage Warnings Contains an extract of St John&#x27;s Wort standardised to hypericin. Traditionally used in Western herbal medicine to: Relieve symptoms of mild anxiety. Support healthy mood balance. Relieve nervous tension. Adults Take 1 tablet three times a day, or as prescribed by a health professional. Take with food. Always read the label and follow the directions for use. Do not during pregnancy or when breastfeeding. St John’s Wort affects the way many prescriptions medicines work -including the oral contraceptive pill. If you are taking other medicines, consult your doctor before use. Avoid excessive skin exposure to sunlight and sunlamps while taking this product. If symptoms persist, talk to your health professional. If you have any pre-existing conditions or are on any medications always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains soya bean products. The Blackmores Difference Ingredients Active ingredients per tablet: Hypericum perforatum (St John''s wort) extact dry conc. 300 mg equivalent dry top flowering 1800 mg (1.8 g) standardised to hypericin 990 micrograms St John&#x27;s Wort Reviews Let&#x27;s stay in touch Instagram Facebook TikTok LinkedIn Back To Top About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom Our Brands & Products Shop Our Products Shop Best Sellers BioCeuticals Blackmores Professional Blackmores Institute Blackmores Education Our Brands & Products Shop Our Products Shop Best Sellers BioCeuticals Blackmores Professional Blackmores Institute Blackmores Education International Markets China Hong Kong SAR iHerb Indonesia Korea Malaysia New Zealand Singapore Taiwan Region Thailand Vietnam International Markets China Hong Kong SAR iHerb Indonesia Korea Malaysia New Zealand Singapore Taiwan Region Thailand Vietnam Terms & Policies Privacy Policy & Practices Terms Of Purchase Terms of Service Posting Guidelines Social Media House Rules Terms & Policies Privacy Policy & Practices Terms Of Purchase Terms of Service Posting Guidelines Social Media House Rules Contacts & FAQs Report a Suspected Adverse Experience Contact Us Ask a Naturopath Product & Purchasing FAQs Blackmores Subscribe Contacts & FAQ