  ('e3fea37a-eb3c-4dcb-ab2e-871d3067407c'::uuid, '0a29b840-7248-4fb4-b26d-b99089b0def0'::uuid, null, 'product_updated', 'codex_blackmores_clean_approval', '{"id":"0a29b840-7248-4fb4-b26d-b99089b0def0","title":"Blackmores Fish Oil 1000","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"40e4806a-5049-4668-8d29-ab36a31202dd","category":null,"currency":"THB","platform":"manual","title_en":"Blackmores Fish Oil 1000","title_th":null,"image_url":"https://images.contentstack.io/v3/assets/blt948bd74310fc0ad0/bltdab79911a7257da3/68bfb499961469255bd0e001/9300807287446-1.webp","brand_name":"blackmores","created_at":"2026-05-21T13:09:45.443507+00:00","source_url":"https://www.blackmores.com.au/products/fish-oil-1000","updated_at":"2026-05-21T13:09:45.459672+00:00","admin_notes":null,"description":"Blackmores Fish Oil 1000 provides high-quality omega-3 to support heart, brain, eye and skin health.","product_url":"https://www.blackmores.com.au/products/fish-oil-1000","label_status":"parsed","price_amount":null,"product_kind":"supplement","description_en":"Blackmores Fish Oil 1000 provides high-quality omega-3 to support heart, brain, eye and skin health.","description_th":null,"normalized_url":"https://www.blackmores.com.au/products/fish-oil-1000","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"dosage":"for use. Read the","locale":"en","parser":"blackmores_structured_ingredients_v2","titleEn":"Blackmores Fish Oil 1000","htmlLength":170649,"validation":{"status":"pass","reasons":[],"summary":"1 matchable canonical fact.","checkedAt":"2026-05-21T13:09:45.457Z","matchableFactCount":1},"description":"Blackmores Fish Oil 1000 provides high-quality omega-3 to support heart, brain, eye and skin health.","descriptionEn":"Blackmores Fish Oil 1000 provides high-quality omega-3 to support heart, brain, eye and skin health.","descriptionTh":null,"extractedText":"Blackmores Fish Oil 1000 Capsules All Products Shop All Products New Products Best Sellers Vegan Certified Women&#x27;s Health Men&#x27;s Health Kid&#x27;s Health Infant & Toddler Nutrition By Category Arthritis, Joint & Bone Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutritional Oils Heart Health Infant & Toddler Nutrition Kids&#x27; Health Men&#x27;s Health Multivitamins Muscle Support Nails, Hair & Skin Preconception, Pregnancy & Breastfeeding Stress Relief & Sleep Support Women&#x27;s Health By Ingredient Calcium CoQ10 Curcumin Echinacea Fish Oil & Omega 3 Glucosamine Iron Magnesium Probiotics Selenium Vitamin B Vitamin C Vitamin D Vitamin E Zinc Health Hub By Categories By Type Latest Articles Action Plans Arthritis, Bone & Joint Beauty & Skincare Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutrition Oils Heart & Cardiovascular Health Kids & Infant Health Men&#x27;s Health Muscle Support & Fitness Preconception, Pregnancy & Breastfeeding Recipes Stress Relief & Sleep Support Women&#x27;s Health Action Plans Articles Recipes Latest Articles About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Pillars Our People & Culture Our Careers Our Ambassadors & Partners Contact us Ask A Naturopath Our Newsroom Blackmores Subscribe Search Home Chevron Icon Horizontal products Chevron Icon Horizontal Blackmores Fish Oil 1000 Size Size 200 capsules 400 capsules Blackmores Fish Oil 1000 is a naturally sourced omega-3 supplement. It is used to support cardiovascular system health, maintain brain health, and support healthy growth and development in children. Rich in EPA and DHA from wild-caught fish, it also helps maintain skin health and supports general health and wellbeing. This formula provides a reliable source of marine omega-3s for people who may not eat fish regularly. Each capsule contains oil tested for mercury, dioxins, and PCBs to meet strict safety standards. Good health changes everything - start with Blackmores Fish Oil 1000. Product Format Capsule Always read the label and follow the directions for use. Read the warnings before purchase. Support For Heart and Cardiovascular Health Skin Health Brain Health Kids Development No Added Yeast No Added Gluten No Added Wheat No Added Dairy Benefits & How To Use Benefits Maintains heart, skin, eye and brain health. Supports general health and wellbeing. Supports healthy growth and development in children. Natural source of omega-3 eicosapentaenoic acid (EPA) and docosahexaenoic acid (DHA). Ideal if you don&#x27;t eat fish 2-3 times per week. Rigorously tested for mercury, dioxins and PCBs. Dosage Take only one recommendation, or as professionally prescribed. Take with food. Adults For heart, skin and general health: Take 2 capsules once a day. For brain and eye health: Take 3 capsules once a day. Children 1+ years For healthy growth and development : Give 2 capsules once a day Children unable to swallow - pierce the capsule, squeeze the content into milk, juice or cereal and consume immediately. Do not swallow whole. Warnings Always read the label and follow the directions for use. Use in children only under adult supervision. Not recommended for children under 1 year. KEEP OUT OF REACH OF CHILDREN. If you have any pre-existing conditions or are on any medications always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains fish, sulfites and soya bean products. Benefits Dosage Warnings Maintains heart, skin, eye and brain health. Supports general health and wellbeing. Supports healthy growth and development in children. Natural source of omega-3 eicosapentaenoic acid (EPA) and docosahexaenoic acid (DHA). Ideal if you don&#x27;t eat fish 2-3 times per week. Rigorously tested for mercury, dioxins and PCBs. Take only one recommendation, or as professionally prescribed. Take with food. Adults For heart, skin and general health: Take 2 capsules once a day. For brain and eye health: Take 3 capsules once a day. Children 1+ years For healthy growth and development : Give 2 capsules once a day Children unable to swallow - pierce the capsule, squeeze the content into milk, juice or cereal and consume immediately. Do not swallow whole. Always read the label and follow the directions for use. Use in children only under adult supervision. Not recommended for children under 1 year. KEEP OUT OF REACH OF CHILDREN. If you have any pre-existing conditions or are on any medications always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains fish, sulfites and soya bean products. The Blackmores Difference Ingredients Active ingredients per capsule: Fish oil - natural 1000 mg (1 g) containing omega-3 triglycerides 300 mg equivalent eicosapentaenoic acid (EPA) 180 mg equivalent docosahexaenoic acid (DHA) 120 mg Fish Oil 1000 Reviews Let&#x27;s stay in touch Instagram Facebook TikTok LinkedIn Back To Top About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom Our Brands & Products Shop Our Products Shop Best Sellers BioCeuticals Blackmores Professional Blackmores Institute Blackmores Education Our Brands & Products Shop Our Products Shop Best Sellers BioCeuticals Blackmores Professional Blackmores Institute Blackmores Education International Markets China Hong Kong SAR iHerb Indonesia Korea Malaysia New Zealand Singapore Taiwan Region Thailand Vietnam International Markets China Hong Kong SAR iHerb Indonesia Korea Malaysia New Z